package codex

import (
	"agent-bridge/internal/domain"
)

// NormalizeCore parses the artifacts generated by Codex into a standard domain.Result.
func NormalizeCore(attemptID string, artifacts []*domain.Artifact) (*domain.Result, error) {
	// For MVP, we return a hardcoded successful result mapping.
	// In reality, this would parse result.json or inspect stdlogs
	
	return &domain.Result{
		Status:             domain.StepStateCompleted,
		Summary:            "Codex executed successfully.",
		NeedsHumanDecision: false,
		Warnings:           nil,
		Questions:          nil,
	}, nil
}
